// Compile the Morning Brief as FOUR messages (repo mounted read-only at /data/swingby):
//   1/4 🔧 BACKEND · 2/4 📱 FRONTEND · 3/4 🧑 HUMAN TODO · 4/4 🌙 NIGHT RECAP
// Each item carries tokenVar so each section can post from its own bot later
// (set TELEGRAM_BOT_TOKEN_BACKEND etc. in n8n.env; falls back to TELEGRAM_BOT_TOKEN).
const fs = require('fs');
const read = (p) => { try { return fs.readFileSync(p, 'utf8'); } catch (e) { return ''; } };
const MEM = '/data/swingby/AGENTS/claude/memory/';

const status = read(MEM + 'STATUS.md');
const todo   = read(MEM + 'HUMAN-TODO.md');
const slog   = read(MEM + 'SESSION_LOG.md');
const onlog  = read('/data/swingby/AGENTS/claude/automation/overnight.log');

// Body of a '## Heading' section ('###' subheadings stay inside).
const section = (src, heading, hashes) => {
  hashes = hashes || '##';
  const esc = heading.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const m = new RegExp('^' + hashes + ' .*' + esc + '.*$', 'm').exec(src);
  if (!m) return '';
  const rest = src.slice(m.index + m[0].length);
  const next = rest.search(new RegExp('^' + hashes + ' ', 'm'));
  return (next === -1 ? rest : rest.slice(0, next)).trim();
};

const checkboxes = (body) => body
  .split('\n')
  .filter((l) => l.startsWith('- [ ]'))
  .map((l) => ('• ' + l.replace(/^- \[ \] /, '').replace(/\*\*/g, '')).slice(0, 220));

const signal = section(status, 'Session End Signal');
const signalLines = signal.split('\n');
const signalHead = (signalLines[0] || 'no signal — read STATUS.md').trim();

// Preferred path: orchestrator wrote an explicit '## Morning Brief' section with
// '### Backend' / '### Frontend' / '### Recap' subsections. Fallback: bucket the
// Session End Signal bullets by keyword (both/neither → recap).
const mb = section(status, 'Morning Brief');
let backend = section(mb, 'Backend', '###');
let frontend = section(mb, 'Frontend', '###');
let recapBody = section(mb, 'Recap', '###');

if (!backend && !frontend) {
  const bullets = signalLines.filter((l) => /^\s*[-•]\s/.test(l)).map((l) => l.replace(/^\s*[-•]\s*/, '• '));
  const prose = signalLines.slice(1).filter((l) => l.trim() && !/^\s*[-•]\s/.test(l)).join('\n');
  const isBack = (b) => /backend|fastapi|pytest|endpoint|\.py\b|supabase|migration|\bsql\b|render|stripe|conftest/i.test(b);
  const isFront = (b) => /mobile|frontend|screen|expo|babel|react|\bRN\b|gesture|navigation|App\.js|\.js\b|safearea/i.test(b);
  const back = [], front = [], rest = [];
  for (const b of bullets) {
    const bb = isBack(b), ff = isFront(b);
    if (bb && !ff) back.push(b);
    else if (ff && !bb) front.push(b);
    else rest.push(b);
  }
  backend = back.join('\n');
  frontend = front.join('\n');
  recapBody = [rest.join('\n'), prose].filter(Boolean).join('\n\n');
}

// Human message: 🌅 morning checkboxes + ⛔ blockers + Next Action.
const morning  = checkboxes(section(todo, 'This morning'));
const blockers = checkboxes(section(todo, 'Blocking'));
const nextActions = section(status, 'Next Action');

const loopNext = (slog.match(/^NEXT:.*$/gm) || []).pop() || '';
const overnightTail = onlog
  ? onlog.trim().split('\n').slice(-6).join('\n')
  : '(overnight loop did not run)';

const today = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Edmonton' });
const cap = (s) => s.trim().slice(0, 3900);

const messages = [
  {
    tokenVar: 'TELEGRAM_BOT_TOKEN_BACKEND',
    text: cap([
      '☀️ SWINGBY BRIEF — ' + today + ' (1/4)',
      'SIGNAL: ' + signalHead,
      '',
      '🔧 BACKEND',
      backend || '• (nothing backend tonight)'
    ].join('\n'))
  },
  {
    tokenVar: 'TELEGRAM_BOT_TOKEN_FRONTEND',
    text: cap([
      '📱 FRONTEND / MOBILE (2/4)',
      '',
      frontend || '• (nothing mobile tonight)'
    ].join('\n'))
  },
  {
    tokenVar: 'TELEGRAM_BOT_TOKEN_HUMAN',
    text: cap([
      '🧑 HUMAN TODO — only you can (3/4)',
      '',
      morning.length ? '🌅 This morning:\n' + morning.join('\n') : '',
      blockers.length ? '⛔ Blocking:\n' + blockers.join('\n') : '⛔ Blocking: (clear)',
      '',
      '— NEXT ACTIONS —',
      nextActions || '(none recorded)'
    ].filter((s) => s !== '').join('\n'))
  },
  {
    tokenVar: 'TELEGRAM_BOT_TOKEN_NIGHT',
    text: cap([
      '🌙 NIGHT RECAP (4/4)',
      '',
      recapBody || '(quiet night)',
      '',
      '— LOOP LOG TAIL —',
      overnightTail,
      '',
      loopNext ? 'LOOP ' + loopNext : ''
    ].join('\n'))
  }
];

return messages.map((m) => ({ json: m }));
